-- Refinamentos dos parametros de marketing.
alter table public.marketing_parametros add column if not exists objetivo_padrao text;
update public.marketing_parametros set objetivo_padrao='Captação de Leads' where plataforma='Google Ads' and objetivo_padrao is null;
update public.marketing_parametros set objetivo_padrao='Mensagens' where plataforma='Meta Ads' and objetivo_padrao is null;
update public.marketing_parametros set investimentos=jsonb_set(jsonb_set(jsonb_set(investimentos,'{local}',case when coalesce((investimentos->>'local')::numeric,0)=0 then '1500'::jsonb else investimentos->'local' end),'{regional}',case when coalesce((investimentos->>'regional')::numeric,0)=0 then '3000'::jsonb else investimentos->'regional' end),'{nacional}',case when coalesce((investimentos->>'nacional')::numeric,0)=0 then '6000'::jsonb else investimentos->'nacional' end) where plataforma='Google Ads';
update public.marketing_parametros set investimentos=jsonb_set(jsonb_set(jsonb_set(investimentos,'{local}',case when coalesce((investimentos->>'local')::numeric,0)=0 then '1000'::jsonb else investimentos->'local' end),'{regional}',case when coalesce((investimentos->>'regional')::numeric,0)=0 then '2000'::jsonb else investimentos->'regional' end),'{nacional}',case when coalesce((investimentos->>'nacional')::numeric,0)=0 then '4000'::jsonb else investimentos->'nacional' end) where plataforma='Meta Ads';
